### 3.2 校验实现 (Rust)

```rust
// gate_report_generator/src/validator.rs
use jsonschema::JSONSchema;

pub struct SchemaValidator {
    schema: JSONSchema,
}

impl SchemaValidator {
    pub fn new(schema_json: &str) -> Result<Self, ValidatorError> {
        let schema = JSONSchema::compile(
            &serde_json::from_str(schema_json)?
        )?;
        Ok(Self { schema })
    }

    /// 单次 Schema 校验
    pub fn validate(&self, report: &GateReport) -> ValidationResult {
        let json_value = serde_json::to_value(report).unwrap();
        let mut errors = Vec::new();
        let mut warnings = Vec::new();

        for error in self.schema.iter_errors(&json_value) {
            errors.push(format!("{}: {}", error.instance_path, error.message));
        }

        ValidationResult {
            passed: errors.is_empty(),
            errors,
            warnings,
        }
    }

    /// 连续 3 次校验
    pub async fn validate_consecutive(
        &self,
        report: &GateReport,
    ) -> Result<SchemaValidationStatus, ValidatorError> {
        let mut consecutive_passes = 0;
        let target = 3;

        for round in 1..=target {
            let result = self.validate(report);

            if result.passed {
                consecutive_passes += 1;
                tracing::info!("Validation round {} passed", round);
            } else {
                tracing::warn!("Validation round {} failed: {:?}", round, result.errors);
                consecutive_passes = 0;  // 重置计数

                // 重新生成报告后继续
                // 实际实现中需要触发重新生成
                break;
            }
        }

        Ok(SchemaValidationStatus {
            consecutive_passes,
            target,
            passed: consecutive_passes >= target,
        })
    }
}
```

